import numpy as np
from scipy.optimize import minimize

class FighterJetSolver:
    def __init__(self):
        self.a_1 = 10
        self.a_2 = 15
        self.max_pilots = 0

    def select_operator(self, current_solution, iteration):
        # Roulette-wheel selection with performance-based weights
        if iteration % 5 == 0:
            return np.random.choice(['select', 'insert', 'remove'], p=[0.3, 0.4, 0.3])
        elif iteration % 3 == 0:
            return 'select'
        else:
            return 'insert' if np.random.rand() < 0.5 else 'remove'

    def apply_operator(self, current_solution, operator):
        if operator == 'select':
            return self.select_pilots(current_solution)
        elif operator == 'insert':
            return self.insert_jet(current_solution)
        elif operator == 'remove':
            return self.remove_jet(current_solution)

    def select_pilots(self, current_solution):
        # Greedy construction heuristic: allocate jets for pilot training
        pilots = 0
        remaining_jets = max(0, min(self.a_1 + self.a_2 - current_solution, 5))
        while remaining_jets > 0:
            jets_to_train = min(remaining_jets, 5)
            pilots += jets_to_train
            remaining_jets -= jets_to_train
        return pilots

    def insert_jet(self, current_solution):
        # Local search swap: insert a jet and check if it improves the solution
        new_solution = current_solution + 1
        if self.is_feasible(new_solution) and self.get_objective_value(new_solution) > self.get_objective_value(current_solution):
            return new_solution
        else:
            return current_solution

    def remove_jet(self, current_solution):
        # Local search swap: remove a jet and check if it improves the solution
        new_solution = max(0, current_solution - 1)
        if self.is_feasible(new_solution) and self.get_objective_value(new_solution) > self.get_objective_value(current_solution):
            return new_solution
        else:
            return current_solution

    def is_feasible(self, solution):
        # Check constraints: total number of jets produced does not exceed the total available
        return solution <= (self.a_1 + self.a_2)

    def get_objective_value(self, solution):
        # Calculate the objective value: number of trained pilots
        return solution * 5

    def solve(self):
        current_solution = 0.0
        for _ in range(100):  # Run for a configurable number of iterations
            operator = self.select_operator(current_solution, _)
            current_solution = self.apply_operator(current_solution, operator)
        return current_solution

