import numpy as np

class CowSheepChickenSolver:
    def __init__(self):
        self.population_size = 100
        self.iterations = 1000
        self.cow_price = 500
        self.sheep_price = 200
        self.chicken_price = 8
        self.cow_feed_cost = 100
        self.sheep_feed_cost = 80
        self.chicken_feed_cost = 5

    def generate_random_solution(self):
        return {'c': random.randint(0, 50), 's': random.randint(0, 40), 'ch': random.randint(0, 30)}

    def evaluate_solution(self, solution):
        total_profit = solution['c'] * (self.cow_price - self.cow_feed_cost) + \
                       solution['s'] * (self.sheep_price - self.sheep_feed_cost) + \
                       solution['ch'] * (self.chicken_price - self.chicken_feed_cost)
        manure_production = 10 * solution['c'] + 5 * solution['s'] + 3 * solution['ch']
        if manure_production > 800:
            return {'profit': 0}
        elif solution['c'] < 10 or solution['s'] < 20 or solution['ch'] > 50 or solution['c'] + solution['s'] + solution['ch'] > 100:
            return {'profit': 0}
        else:
            return {'profit': total_profit}

    def mutate(self, solution):
        if random.random() < 0.5:
            c = 'c' if random.choice(['c', 's', 'ch']) == 'c' else random.choice(['s', 'ch'])
            solution[c] += random.randint(-10, 10)
            return {'profit': self.evaluate(solution)['profit']}
        return solution

    def crossover(self, parent1, parent2):
        child = {}
        for key in ['c', 's', 'ch']:
            if random.random() < 0.5:
                child[key] = parent1.get(key, 0)
            else:
                child[key] = parent2.get(key, 0)
        return {'profit': self.evaluate(child)['profit']}

    def selection(self, solutions):
        scores = [solution['profit'] for solution in solutions]
        return [solutions[i] for i in np.argsort(scores)[::-1]]

    def adapt_selection(self, best_solution):
        if random.random() < 0.5:
            return 'roulette'
        elif random.random() < 0.8:
            return 'reinforcement_learning'
        else:
            return 'choice_function'

    def run_solver(self):
        population = [self.generate_random_solution() for _ in range(self.population_size)]
        best_solution = None
        for _ in range(self.iterations):
            new_population = []
            selection_strategy = self.adapt_selection(best_solution)
            if selection_strategy == 'roulette':
                weights = [solution['profit'] for solution in population]
                for _ in range(len(population)):
                    parent1, parent2 = random.choices(population, weights=weights)[0], random.choices(population, weights=weights)[0]
                    child = self.crossover(parent1, parent2)
                    new_population.append(self.mutate(child))
            elif selection_strategy == 'reinforcement_learning':
                for solution in population:
                    if solution['profit'] > best_solution['profit']:
                        best_solution = solution
                for _ in range(len(population)):
                    parent1, parent2 = random.choices([solution for solution in population if solution['profit'] > best_solution['profit']], weights=[solution['profit'] - best_solution['profit'] for solution in population])[0], random.choices([solution for solution in population if solution['profit'] > best_solution['profit']], weights=[solution['profit'] - best_solution['profit'] for solution in population])[0]
                    child = self.crossover(parent1, parent2)
                    new_population.append(self.mutate(child))
            elif selection_strategy == 'choice_function':
                recency_scores = [i / len(population) for i in range(len(population))]
                improvement_scores = [(solution['profit'] - best_solution['profit'])**2 for solution in population]
                diversity_scores = []
                for s1, s2 in zip(population, [best_solution]):
                    temp = sum((s1.get(key, 0) - s2.get(key, 0))**2 for key in ['c', 's', 'ch'])
                    diversity_scores.append(temp)
                parents = random.choices(population, weights=[recency * imp * div for recency, imp, div in zip(recency_scores, improvement_scores, diversity_scores)], k=2)
                child = self.crossover(parents[0], parents[1])
                new_population.append(self.mutate(child))
            population = new_population
        print(f"OBJECTIVE_VALUE: {best_solution['profit']}")

