ports = ['Genoa', 'Venice', 'Ancona', 'Naples', 'Bari']
distances = {
    'Verona': {'Genoa': 290, 'Venice': 115, 'Ancona': 355, 'Naples': 715, 'Bari': 810},
    'Perugia': {'Genoa': 380, 'Venice': 340, 'Ancona': 165, 'Naples': 380, 'Bari': 610},
    'Rome': {'Genoa': 505, 'Venice': 530, 'Ancona': 285, 'Naples': 220, 'Bari': 450},
    'Pescara': {'Genoa': 655, 'Venice': 450, 'Ancona': 155, 'Naples': 240, 'Bari': 315},
    'Taranto': {'Genoa': 1010, 'Venice': 840, 'Ancona': 550, 'Naples': 305, 'Bari': 95},
    'Lamezia': {'Genoa': 1072, 'Venice': 1097, 'Ancona': 747, 'Naples': 372, 'Bari': 333}
}

empty_containers = [10, 12, 20, 24, 18, 40]
demand = [20, 15, 25, 33, 21]

# Simulated Annealing parameters
initial_temperature = 1000.0
final_temperature = 1e-5
cooling_rate = 0.95

def calculate_cost(x):
    return sum([min(2, max(0, x[i][j])) * distances[warehouses[i]][ports[j]] for i in range(6) for j in range(len(ports))])

def penalty_function(x, empty_containers, demand):
    total_penalty = 0
    for i in range(6):
        if sum(x[i]) > empty_containers[i]:
            total_penalty += (sum(x[i]) - empty_containers[i])**2
    for j in range(len(demand)):
        if sum([x[i][j] for i in range(6)]) < demand[j]:
            total_penalty += (demand[j] - sum([x[i][j] for i in range(6)]))**2
    return total_penalty

def simulated_annealing():
    temperature = initial_temperature
    x0 = [[random.random() * 2 for _ in range(len(ports))] for _ in range(6)]

    while temperature > final_temperature:
        new_x = [np.array(x) + np.random.normal(size=(1, len(ports))) for x in x0]

        cost_new = calculate_cost(new_x)
        cost_old = calculate_cost(x0)

        delta_energy = cost_new - cost_old

        if delta_energy < 0 or random.random() < np.exp(-delta_energy / temperature):
            x0 = new_x
        else:
            x0 = [[min(2, max(0, x)) for x in row] for row in x0]

        temperature *= cooling_rate

    return x0

def main():
    solution = simulated_annealing()

    objective_value = calculate_cost(solution)

    print(f"OBJECTIVE_VALUE: {objective_value:.4f}")

