    'Lamezia': {'Genoa': 1072, 'Venice': 1097, 'Ancona': 747, 'Naples': 372, 'Bari': 333}
}

demand_matrix = {
    'Genoa': 20,
    'Venice': 15,
    'Ancona': 25,
    'Naples': 33,
    'Bari': 21
}

# Define low-level heuristic operators (constructive + local search)
def greedy_construction():
    solution = {}
    for warehouse in Warehouses:
        for port, demand in demand_matrix.items():
            if demand > 0 and warehouse in distance_matrix and port in distance_matrix[warehouse]:
                for _ in range(min(demand, int((distance_matrix[warehouse][port] / 30) * sum(distance_matrix[warehouse].values())))):
                    solution[(warehouse, port)] = 1
    return solution

def local_search_swap(solution):
    best_solution = solution.copy()
    for warehouse in Warehouses:
        for port, demand in demand_matrix.items():
            if demand > 0 and warehouse in distance_matrix and port in distance_matrix[warehouse]:
                for _ in range(min(demand, int((distance_matrix[warehouse][port] / 30) * sum(distance_matrix[warehouse].values())))):
                    best_solution[(warehouse, port)] = 1
    return best_solution

def perturbation(solution):
    new_solution = solution.copy()
    for warehouse in Warehouses:
        for port, demand in demand_matrix.items():
            if demand > 0 and warehouse in distance_matrix and port in distance_matrix[warehouse]:
                if randint(0, 1) == 1:
                    new_solution[(warehouse, port)] = int(not bool(new_solution.get((warehouse, port), 0)))
    return new_solution

# Define hyper-heuristic with adaptive selection mechanism
class HyperHeuristic():
    def __init__(self):
        self.operators = [greedy_construction, local_search_swap, perturbation]
        self.weights = [1/3, 1/3, 1/3]  # initial weights for roulette-wheel selection

    def select_operator(self, performance_history):
        # Roulette-wheel selection with performance-based weights
        total_weight = sum(self.weights)
        selected_operator_index = np.random.choice(len(self.operators), p=[weight / total_weight for weight in self.weights])
        return self.operators[selected_operator_index]

    def run(self, num_iterations):
        solution_history = []
        for _ in range(num_iterations):
            operator = self.select_operator(solution_history)
            if len(solution_history) > 0:
                new_solution = operator()
            else:
                new_solution = greedy_construction()  # initialize with constructive heuristic
            if len(new_solution) > 0:
                solution_history.append(new_solution)

        # Find best solution
        best_solution = min(solution_history, key=lambda x: sum(demand_matrix[port] - sum((x.get((warehouse, port), 0) for warehouse in Warehouses)) for port in Ports))

        return dict(best_solution)

# Run hyper-heuristic solver
